mapper.select:
SELECT t.*, p.IF_NAME, p.IF_DESCR FROM P_TRAFFIC_T t INNER JOIN r_port_t p ON t.DEVICE_ID = p.DEVICE_ID AND t.IF_INDEX = p.IF_INDEX WHERE t.DEVICE_ID = #{deviceId}
AND t.COLLECTED_AT BETWEEN #{startDate} AND #{endDate}
AND t.COLLECTED_AT >= DATE_SUB(NOW(), INTERVAL #{minutes} MINUTE)
AND p.IF_OPER_STATUS = 1 AND p.DELETE_AT IS NULL ORDER BY t.IF_INDEX, t.COLLECTED_AT ASC

SELECT t.*, p.IF_NAME, p.IF_DESCR FROM P_TRAFFIC_T t INNER JOIN r_port_t p ON t.DEVICE_ID = p.DEVICE_ID AND t.IF_INDEX = p.IF_INDEX WHERE t.DEVICE_ID IN
#{id}
AND t.COLLECTED_AT BETWEEN #{startDate} AND #{endDate} AND p.IF_OPER_STATUS = 1 AND p.DELETE_AT IS NULL ORDER BY t.DEVICE_ID, t.IF_INDEX, t.COLLECTED_AT ASC

SELECT t.DEVICE_ID, t.IF_INDEX, FROM_UNIXTIME(FLOOR(UNIX_TIMESTAMP(t.COLLECTED_AT)/#{intervalSec})*#{intervalSec}) AS COLLECTED_AT, ROUND(AVG(t.IN_BPS), 2) AS IN_BPS, ROUND(AVG(t.IN_HIGH_BPS), 2) AS IN_HIGH_BPS, ROUND(AVG(t.OUT_BPS), 2) AS OUT_BPS, ROUND(AVG(t.OUT_HIGH_BPS), 2) AS OUT_HIGH_BPS, ROUND(AVG(t.IN_USED_PERCENT), 2) AS IN_USED_PERCENT, ROUND(AVG(t.IN_HIGH_USED_PERCENT), 2) AS IN_HIGH_USED_PERCENT, ROUND(AVG(t.OUT_USED_PERCENT), 2) AS OUT_USED_PERCENT, ROUND(AVG(t.OUT_HIGH_USED_PERCENT), 2) AS OUT_HIGH_USED_PERCENT, MAX(p.IF_NAME) AS IF_NAME, MAX(p.IF_DESCR) AS IF_DESCR FROM P_TRAFFIC_T t INNER JOIN r_port_t p ON t.DEVICE_ID = p.DEVICE_ID AND t.IF_INDEX = p.IF_INDEX WHERE t.DEVICE_ID IN
#{id}
AND t.COLLECTED_AT BETWEEN #{startDate} AND #{endDate} AND p.IF_OPER_STATUS = 1 AND p.DELETE_AT IS NULL GROUP BY t.DEVICE_ID, t.IF_INDEX, FLOOR(UNIX_TIMESTAMP(t.COLLECTED_AT)/#{intervalSec}) ORDER BY t.DEVICE_ID, t.IF_INDEX, COLLECTED_AT ASC
